#include <bits/stdc++.h>#include <ext/pb_ds/assoc_container.hpp> // Common file#include <ext/pb_ds/tree_policy.hpp> // Including tree_order_statistics_node_updateusing namespace std;using namespace __gnu_pbds;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define dbg(...)#endif#define endl "\n"#define FAST ios_base::sync_with_stdio(false); cin.tie(NULL);#define ll long long#define pb(n) push_back(n)#define F first#define S second#define mp(x, y) make_pair(x, y)#define yes cout << "YES" << endl;#define no cout << "NO" << endl;#define nop cout << -1 << endl;#define int ll#define ordered_set tree<pair<int, int>, null_type, less<pair<int, int>>, rb_tree_tag, tree_order_statistics_node_update>const ll sup = 1e18;const ll inf = -1e18;const ll mod = 1e9 + 7;const int N_Max = 2e5 + 7;const int Nax = 15;const int LOG = 18;const int BITS = 30;const int ALPHA = 26;ll gcd(ll a , ll b) {return b ? gcd(b , a % b) : a;}ll lcm(ll a , ll b) {return (a * b) / gcd(a , b);}ll inv(ll N) {if (N == 1) return 1; return (mod - ((mod / N) * inv(mod % N)) % mod) % mod;} vector<int> adj[N_Max], comp;int a[N_Max], in_deg[N_Max];ll best[N_Max], res[N_Max];int vis[N_Max], sub[N_Max];int in_cyc[N_Max];int nxt[N_Max];ll sum[N_Max];int N; void init(){    comp.clear();    for (int i = 1; i <= N; i++){        adj[i].clear();        in_deg[i] = best[i] = res[i] = vis[i] = sub[i] = in_cyc[i] = nxt[i] = sum[i] = 0;    }} void dfs_init(int Node){    vis[Node]++;    comp.pb(Node);    if (!vis[nxt[Node]]) dfs_init(nxt[Node]);    for (int child : adj[Node])        if (!vis[child]) dfs_init(child);} void dfs(int Node, int val){    sub[Node] = 1;    for (int child : adj[Node]){        if (in_cyc[child]) continue;        res[child] = val;        dfs(child, val + 1);        sub[Node] += sub[child];    }} void get_ans(int Node, int id){    for (int child : adj[Node]){        if (in_cyc[child]) continue;        ll curr = res[child] * sub[child];        best[id] = min(best[id], sum[id] - curr);        get_ans(child, id);    }} void work(int id){    for (int u : comp) vis[u] = 0;    queue<int> q;    for (int u : comp){        if (!in_deg[u]){            vis[u]++;            q.push(u);        }    }    while (!q.empty()){        int Node = q.front();        q.pop();        in_deg[nxt[Node]]--;        if (!in_deg[nxt[Node]]){            vis[nxt[Node]]++;            q.push(nxt[Node]);        }    }    vector<int> cyc;    for (int u : comp){        if (!vis[u]){            vis[u]++;            cyc.pb(u);            break;        }    }    assert(!cyc.empty());    while (!vis[nxt[cyc.back()]]) cyc.pb(nxt[cyc.back()]);    for (int u : cyc){        vis[u]++;        in_cyc[u]++;    }    int sz = (int)cyc.size();    for (int u : cyc){        res[u] = sz - 1;        dfs(u, sz);    }    ll tot = 0;    for (int u : comp) tot += res[u];    sum[id] = tot;    best[id] = tot;    vector<ll> pref;    for (int u : cyc) pref.pb(sub[u]);    for (int u : cyc) pref.pb(sub[u]);    for (int i = 1; i < (int)pref.size(); i++) pref[i] += pref[i - 1];    if (sz > 1){        ll S = 0;        for (int i = 0; i < sz; i++) S += i * sub[cyc[i]];        best[id] = min(best[id], tot - S);        for (int i = 1; i <= (int)pref.size() - sz; i++){            S -= pref[i + sz - 2] - pref[i - 1];            S += (sz - 1) * sub[cyc[(i + sz - 1) % sz]];            best[id] = min(best[id], tot - S);        }    }    for (int u : cyc) get_ans(u, id);} void solve(){    cin >> N;    init();    for (int i = 1; i <= N; i++){        cin >> a[i];        nxt[i] = a[i];        adj[a[i]].pb(i);        in_deg[a[i]]++;    }    int curr = 0;    for (int i = 1; i <= N; i++){        if (vis[i]) continue;        comp.clear();        dfs_init(i);        curr++;        work(curr);    }    ll tot = 0;    for (int i = 1; i <= N; i++) tot += res[i];    ll ans = tot;    for (int i = 1; i <= curr; i++)        ans = min(ans, tot - sum[i] + best[i]);    cout << ans << endl;} int32_t main(){    FAST    #ifndef ONLINE_JUDGE    freopen("input.txt","r",stdin);    freopen("output.txt","w",stdout);    #endif    freopen("cheat.in","r",stdin);    int tc = 1;    cin >> tc;    while (tc--) solve();    return 0;}